{
    std::cout << divide(10, 2) << '\n';
    return 0;
}
```

The programmer wants to recover from bad input and re-prompt the user. What is the bug?

```cpp
#include <iostream>
int main()
{
    int x;
    if (!(std::cin >> x))
    {
        std::cin.clear();
        std::cout << "Invalid input, try again\n";
        std::cin >> x;
    }
    std::cout << x << '\n';
    return 0;
}
```

What does this program print?

```cpp
#include <iostream>
int classify(int n)
{
    if (n >= 0)
        return 1;
    return -1;
}
int main()
{
    std::cout << (classify(0) == 1 ? "PASS" : "FAIL") << '\n';
    std::cout << (classify(-5) == -1 ? "PASS" : "FAIL") << '\n';
    return 0;
}
```
